	PyObj->SelfCreatedValue = false;
#else
	PyObj->Value = (FPostProcessSettings*)FMemory::Malloc(sizeof(FPostProcessSettings), alignof(FPostProcessSettings));
	NePyBase::EnsureCopyToStructSafely<FPostProcessSettings>(InStructProp, PyObj->Value);
	InStructProp->Struct->CopyScriptStruct(PyObj->Value, InBuffer);
	PyObj->SelfCreatedValue = true;
#endif
